var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"와아~ 못 본 사이에 새 팔을 달았네, 고고학부장님?","JPN":"わあ～ちょっと見ない間に新しい腕をつけたね、考古学部長？","ENG":"Wow! I guess you got yourself a new arm there!","TWN":"哇～好久沒見，考古學教授戴上了新手臂呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그렇다네, 리벳.","JPN":"そうだよ、リベット。","ENG":"That's right, Rivet.","TWN":"啊，是里維啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"인외의 신체에 대해서는 흥미가 있었네만, 이런 식으로 경험하게 될 줄은 몰랐어.","JPN":"人外の身体には元々興味があったが、こんな形で経験することになるとは知らなかったよ。","ENG":"I've always had an interest in nonhuman body parts, but I never expected to experience it like this.","TWN":"我對人類外的身體很感興趣，但沒想到會以這種方式體驗。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"어떤가? 기능적으로 보면, 인간의 그것보다 우수하다네.","JPN":"どうかね？　機能面では人間のそれより優れているが。","ENG":"What do you think? Functionally, it surpasses that of a human's.","TWN":"怎麼樣？從功能上來說，比人類的要優秀多了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"대박~ 어울려!","JPN":"すっごく似合ってる！","ENG":"Cool! It suits you!","TWN":"天啊～很適合你！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"포위당했군요.","JPN":"囲まれました。","ENG":"We are surrounded.","TWN":"我們被包圍了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"우리의 움직임을 눈치채고, 이곳에 병력을 집중시킨 모양입니다.","JPN":"私たちの動きに気づいて、ここに兵力を集中させていたようですね。","ENG":"They must have noticed our movement patterns and focused their forces here.","TWN":"看樣子是察覺到了我們的動向，所以把兵力集中到了這裡。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"상관없어.","JPN":"構わない。","ENG":"It doesn't matter.","TWN":"無所謂。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"여기까지 온 이상, 눈에 거슬리는 건 전부 박살 내 버리면 그만이야.","JPN":"ここまで来た以上、目障りは全部ぶっ飛ばすまでだ。","ENG":"We've come all this way. I'm just going to destroy everything in my way.","TWN":"既然都到這裡了，把看不順眼的都給滅了吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"미안하지만, 자네들에게 성배를 넘겨줄 수는 없네.","JPN":"すまないが、君たちに聖杯は渡せない。","ENG":"I'm afraid you won't be taking the Holy Grail.","TWN":"抱歉，我不能把聖杯交給你們。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"신적 존재가 탄생하는 순간을 내 눈으로 직접 볼 수 있는 마지막 기회니까 말이야.","JPN":"神的存在が生まれる瞬間をこの目で確認できる最後の機会だからね。","ENG":"Since, this is the last chance I'll be able to witness the birth of a godly entity.","TWN":"因為這是我最後一次能親眼看到神之存在誕生的機會。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"신은 과연 선할까? 악할까?","JPN":"神は善なる存在か、悪か。","ENG":"Is god good or evil?","TWN":"神是善良的？還是邪惡的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그조차 아니라면 연약한 인간의 이지를 초월한 무언가일까……!","JPN":"それとも脆く弱い人間の理知を超越した何かか……！","ENG":"Or is god an entity that transcends the intellectual capacity of puny humans...?!","TWN":"如果二者皆不是，那難道是超越脆弱人類的理智嗎……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"오직 성배만이…… 그 해묵은 궁금증을 해결할 유일한 수단이란 말일세!","JPN":"聖杯こそが……この古くからの疑問に答えを提示してくれる唯一のものなのだ！","ENG":"The Holy Grail... is the only way to get the answers to those age-old questions!","TWN":"唯有聖杯……才是解決這些陳年問題的唯一手段！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"지금 이 순간에도 조금씩 세상은 멸망을 향해 다가가고 있다.","JPN":"今この瞬間にも世界は少しずつ滅亡に近づいている。","ENG":"The end of the world is slowly approaching even as we speak.","TWN":"即使是現在，世界也朝著滅亡更近一步。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"마음만 먹으면 이 세계를 박살내어 버릴 존재들이 심연 속에서 때를 기다리고 있지.","JPN":"その気になれば、この世界を粉々にしてしまう存在が深淵の中で時を待っているのだ。","ENG":"In the depths of the abyss, there are unimaginable beings that could destroy this world on a whim.","TWN":"只要下定決心，就可以將世界毀滅掉的存在，正在深淵裡伺機而動。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그런데 우리의 신은 무엇을 하고 있지?","JPN":"それなのに私たちの神は何をしている？","ENG":"But what is \\"our\\" God doing?","TWN":"但我們的神有什麼作為呢？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"……그리고 신의 대리인을 자청하며 거들먹거리던 우리 사제들은?","JPN":"……そして神の代理人を自称しながら偉ぶっていた私たち司祭は？","ENG":"And what about our arrogant priests who call themselves the messengers of God?","TWN":"……還有那些以神的代言人自居，而得意洋洋的祭司們呢？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신은…… 저로 하여금, 그 남자를 연상케 하는군요.","JPN":"あなたは……まるであの男のようなことを言いますね。","ENG":"You... remind me of that man.","TWN":"你……讓我，聯想到了那個男人。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주를 모욕하던 그 가증스럽고, 역겨운 변절자를……!","JPN":"主を侮辱していた、あの厚かましくうっとうしい裏切者のような……！","ENG":"That despicable, disgusting man who insulted the lord...!","TWN":"那個侮辱主的，面目可憎的叛徒……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"학회의 추종자, 당신의 목적은 저자의 신병이었을 겁니다. 그렇지 않나요?","JPN":"学界の取り巻き、あなたの目的は彼の身柄だったはずです。違いますか？","ENG":"Follower of the Society, your objective was to capture him, was it not?","TWN":"學會的追隨者，你的目的是帶走那個人，對吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"맞아, 수녀님! 나는 고고학부장만 레지나 앞으로 데려가면 돼!","JPN":"そうだよ、シスター！　私は考古学部長をレジーナのとこに連れて行けたらそれでいい！","ENG":"Correct, Sister! I just need to take the Dean of Archeology to Regina!","TWN":"沒錯，修女！我只要帶考古學教授到蕾佳娜前面去就行了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};